@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=JetBrains+Mono:wght@400;500&family=Space+Grotesk:wght@500&display=swap');
@import './tokens.css';

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  background: var(--background);
  color: var(--on-surface);
  font-family: var(--font-body);
  font-size: 14px;
  line-height: 1.5;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}

a { color: var(--primary); text-decoration: none; transition: opacity 0.2s; }
a:hover { opacity: 0.8; text-decoration: none; }

.app-layout {
  display: flex;
  min-height: 100vh;
}

.sidebar {
  width: 240px;
  border-right: 1px solid var(--outline);
  display: flex;
  flex-direction: column;
  position: sticky;
  top: 0;
  height: 100vh;
  background: var(--background);
  flex-shrink: 0;
}

.sidebar-header {
  height: 56px;
  padding: 0 16px;
  display: flex;
  align-items: center;
  gap: 12px;
  border-bottom: 1px solid var(--outline);
}

.sidebar-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px 0;
}

.sidebar-section {
  margin-bottom: 24px;
}

.sidebar-section-title {
  padding: 0 16px;
  font-size: 11px;
  font-weight: 600;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 8px;
}

.sidebar-nav {
  display: flex;
  flex-direction: column;
}

.sidebar-nav-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 8px 16px;
  color: var(--on-surface);
  font-size: 13px;
  font-weight: 500;
  transition: background 0.2s;
}

.sidebar-nav-item:hover {
  background: var(--surface-dim);
  opacity: 1;
}

::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: var(--outline);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--on-surface-variant);
}

.sidebar-nav-item.active {
  background: var(--surface-dim);
  color: var(--on-surface);
  border-right: 2px solid var(--primary);
}


.sidebar-nav-item svg {
  color: var(--on-surface-variant);
}

.sidebar-nav-item.active svg {
  color: var(--primary);
}

.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.header {
  border-bottom: 1px solid var(--outline);
  padding: 0 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 56px;
  position: sticky;
  top: 0;
  background: var(--background);
  z-index: 10;
}

.container { width: 100%; max-width: 1400px; margin: 0 auto; padding: 32px 48px; }


.page-title {
  font-family: var(--font-headline);
  font-size: 24px;
  font-weight: 500;
  letter-spacing: -0.02em;
  margin-bottom: 32px;
  color: var(--on-surface);
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 16px;
  margin-bottom: 40px;
}
.stat-card {
  background: var(--surface-container);
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  padding: 24px;
}
.stat-label {
  font-size: 11px;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 12px;
  font-family: var(--font-headline);
}
.stat-value {
  font-size: 32px;
  font-weight: 500;
  color: var(--on-surface);
  line-height: 1;
  font-family: var(--font-headline);
  letter-spacing: -0.02em;
}
.stat-sub {
  font-size: 12px;
  color: var(--on-surface-variant);
  margin-top: 8px;
}

.charts-grid {
  display: grid;
  grid-template-columns: 2fr 1fr;
  gap: 16px;
  margin-bottom: 40px;
}
@media (max-width: 768px) { .charts-grid { grid-template-columns: 1fr; } }
.chart-card {
  background: var(--surface);
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  padding: 24px;
}
.chart-title {
  font-size: 11px;
  font-weight: 500;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 24px;
  font-family: var(--font-headline);
}
canvas { max-height: 240px; }

.section-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
}
.section-title {
  font-family: var(--font-headline);
  font-size: 16px;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}
.section-link { font-size: 12px; color: var(--primary); font-weight: 500; }

.table-wrap {
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  overflow: hidden;
}
table { width: 100%; border-collapse: collapse; }
thead th {
  padding: 12px 16px;
  text-align: left;
  font-size: 11px;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  border-bottom: 1px solid var(--outline);
  background: var(--surface-dim);
  font-family: var(--font-headline);
}
tbody td {
  padding: 14px 16px;
  border-bottom: 1px solid var(--outline);
  vertical-align: middle;
}
tbody tr:last-child td { border-bottom: none; }
tbody tr:hover td { background: var(--surface-dim); }

.btn-icon {
  background: transparent;
  border: none;
  color: var(--on-surface-variant);
  cursor: pointer;
  padding: 4px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 4px;
}
.btn-icon:hover {
  background: var(--surface-dim);
  color: var(--on-surface);
}

.badge {
  display: inline-flex;
  align-items: center;
  padding: 2px 6px;
  border-radius: 4px;
  font-size: 11px;
  font-weight: 500;
  line-height: 1;
  background: var(--surface-container);
  color: var(--on-surface-variant);
  border: 1px solid var(--outline);
}

.badge-primary { background: rgba(59, 130, 246, 0.1); color: var(--primary); border-color: rgba(59, 130, 246, 0.2); }
.badge-secondary { background: rgba(245, 158, 11, 0.1); color: #F59E0B; border-color: rgba(245, 158, 11, 0.2); }

.session-group {
  margin-bottom: 32px;
}

.session-group-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--on-surface);
  margin-bottom: 12px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.session-list {
  display: flex;
  flex-direction: column;
  border-top: 1px solid var(--outline);
}

.session-item {
  display: grid;
  grid-template-columns: 1fr auto;
  align-items: center;
  gap: 16px;
  padding: 12px 0;
  border-bottom: 1px solid var(--outline);
  transition: background 0.2s;
}

.session-item:hover {
  background: var(--surface-dim);
}

.avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--surface-container);
  border: 1px solid var(--outline);
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

.session-summary {
  font-size: 14px;
  color: var(--on-surface);
  line-height: 1.4;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.session-header {
  margin-bottom: 48px;
}

.session-title {
  font-size: 24px;
  font-weight: 600;
  color: var(--on-surface);
  line-height: 1.3;
  margin-bottom: 16px;
  letter-spacing: -0.01em;
}

.session-metadata-bar {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
  padding-bottom: 24px;
  border-bottom: 1px solid var(--outline);
}

.meta-item {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  color: var(--on-surface-variant);
}

.session-detail-layout {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 280px;
  gap: 48px;
}

.timeline {
  display: flex;
  flex-direction: column;
  gap: 32px;
  position: relative;
}

.timeline::before {
  content: "";
  position: absolute;
  left: 16px;
  top: 0;
  bottom: 0;
  width: 1px;
  background: var(--outline);
  z-index: 0;
}

.timeline-item {
  display: flex;
  gap: 24px;
  position: relative;
  z-index: 1;
}

.timeline-dot {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--background);
  border: 1px solid var(--outline);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.timeline-content {
  flex: 1;
  min-width: 0;
}

.message-card {
  background: var(--surface);
  border: 1px solid var(--outline);
  border-radius: 8px;
  padding: 16px;
}

.message-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
  font-size: 12px;
  color: var(--on-surface-variant);
}

.message-text {
  font-size: 14px;
  line-height: 1.6;
  color: var(--on-surface);
}

.message-text p {
  margin-bottom: 12px;
}

.message-text p:last-child {
  margin-bottom: 0;
}

.message-text pre {
  background: var(--surface-dim);
  padding: 12px;
  border-radius: 6px;
  overflow-x: auto;
  font-family: var(--font-mono);
  font-size: 13px;
  margin-bottom: 12px;
  border: 1px solid var(--outline);
}

.message-text code {
  background: var(--surface-dim);
  padding: 2px 4px;
  border-radius: 4px;
  font-family: var(--font-mono);
  font-size: 13px;
}

.message-text pre code {
  background: transparent;
  padding: 0;
}

.message-text ul, .message-text ol {
  margin-left: 20px;
  margin-bottom: 12px;
}

.message-text li {
  margin-bottom: 4px;
}

.message-text a {
  color: var(--primary);
  text-decoration: underline;
}

.message-text h1, .message-text h2, .message-text h3, .message-text h4 {
  margin-top: 16px;
  margin-bottom: 12px;
  font-family: var(--font-headline);
}

.tool-call {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-top: 12px;
}

.tool-call-header {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 13px;
  font-weight: 500;
  color: var(--on-surface);
  cursor: pointer;
}

.tool-call-content {
  background: var(--surface-dim);
  border: 1px solid var(--outline);
  border-radius: 4px;
  padding: 12px;
  font-family: var(--font-mono);
  font-size: 12px;
  overflow-x: auto;
}

.detail-sidebar-section {
  margin-bottom: 32px;
}

.detail-sidebar-title {
  font-size: 11px;
  font-weight: 600;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 12px;
}

.filter-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.filter-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: 13px;
  color: var(--on-surface);
}

.filter-item input {
  width: 14px;
  height: 14px;
}

/* Session tabs */
.session-tabs {
  display: flex;
  align-items: center;
  border-bottom: 1px solid var(--outline);
  margin-bottom: 32px;
  margin-top: -24px;
}

.session-tab {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 16px;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  font-size: 14px;
  font-weight: 500;
  color: var(--on-surface-variant);
  cursor: pointer;
  margin-bottom: -1px;
  transition: color 0.15s;
}

.session-tab:hover { color: var(--on-surface); }

.session-tab.active {
  color: var(--on-surface);
  border-bottom-color: var(--primary);
}

.tab-badge {
  background: var(--surface-container);
  border: 1px solid var(--outline);
  border-radius: 10px;
  padding: 1px 7px;
  font-size: 11px;
  font-weight: 500;
  color: var(--on-surface-variant);
}

/* Changes tab layout */
.changes-layout {
  display: grid;
  grid-template-columns: 280px 1fr;
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  overflow: hidden;
  min-height: 500px;
}

.changes-file-list {
  border-right: 1px solid var(--outline);
  overflow-y: auto;
  background: var(--surface);
}

.changes-file-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  cursor: pointer;
  border-bottom: 1px solid var(--outline);
  transition: background 0.15s;
}

.changes-file-item:hover { background: var(--surface-dim); }
.changes-file-item.selected { background: var(--surface-container); }

.file-status-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  border-radius: 3px;
  font-size: 10px;
  font-weight: 700;
  flex-shrink: 0;
}

.status-M { background: rgba(59, 130, 246, 0.15); color: var(--primary); }
.status-A { background: rgba(34, 197, 94, 0.15); color: var(--tertiary); }
.status-D { background: rgba(248, 113, 113, 0.15); color: var(--error); }
.status-R { background: rgba(245, 158, 11, 0.15); color: #F59E0B; }

.changes-file-name {
  flex: 1;
  min-width: 0;
  overflow: hidden;
}

.changes-file-name > span:first-child {
  display: block;
  font-size: 13px;
  color: var(--on-surface);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.changes-file-dir {
  display: block;
  font-size: 11px;
  color: var(--on-surface-variant);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.changes-file-stats {
  display: flex;
  gap: 6px;
  flex-shrink: 0;
  font-size: 12px;
  font-family: var(--font-mono);
}

.stat-add { color: var(--tertiary); }
.stat-del { color: var(--error); }

/* Diff viewer */
.changes-diff-panel {
  overflow: auto;
  background: var(--background);
}

.diff-viewer {
  font-family: var(--font-mono);
  font-size: 12px;
}

.diff-file-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 16px;
  border-bottom: 1px solid var(--outline);
  background: var(--surface-dim);
  position: sticky;
  top: 0;
  z-index: 1;
}

.diff-file-path {
  font-size: 13px;
  font-weight: 500;
  color: var(--on-surface);
  font-family: var(--font-mono);
}

.diff-file-stats {
  display: flex;
  gap: 8px;
  font-family: var(--font-mono);
  font-size: 12px;
}

.diff-hunk-header {
  padding: 4px 12px;
  background: rgba(59, 130, 246, 0.07);
  color: var(--on-surface-variant);
  font-size: 12px;
  font-family: var(--font-mono);
  border-top: 1px solid var(--outline);
  border-bottom: 1px solid var(--outline);
}

.diff-table {
  width: 100%;
  border-collapse: collapse;
}

.diff-line-num {
  width: 44px;
  min-width: 44px;
  text-align: right;
  padding: 1px 8px;
  color: var(--on-surface-variant);
  user-select: none;
  font-size: 11px;
  border-right: 1px solid var(--outline);
  vertical-align: top;
  opacity: 0.6;
}

.diff-line-marker {
  width: 20px;
  min-width: 20px;
  text-align: center;
  padding: 1px 4px;
  font-size: 12px;
  user-select: none;
  border-right: 1px solid var(--outline);
  vertical-align: top;
}

.diff-line-content {
  padding: 1px 8px;
  white-space: pre;
  tab-size: 2;
  font-size: 12px;
  vertical-align: top;
  width: 100%;
}

.diff-line-add .diff-line-num,
.diff-line-add .diff-line-marker,
.diff-line-add .diff-line-content { background: rgba(34, 197, 94, 0.07); }
.diff-line-add .diff-line-marker,
.diff-line-add .diff-line-content { color: var(--tertiary); }

.diff-line-remove .diff-line-num,
.diff-line-remove .diff-line-marker,
.diff-line-remove .diff-line-content { background: rgba(248, 113, 113, 0.07); }
.diff-line-remove .diff-line-marker,
.diff-line-remove .diff-line-content { color: var(--error); }

.diff-empty {
  padding: 48px;
  text-align: center;
  color: var(--on-surface-variant);
  font-size: 13px;
}



/* Context Timeline */
.context-timeline {
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding: 24px 0;
}

.interaction-item {
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  overflow: hidden;
  background: var(--surface);
}

.interaction-header {
  padding: 12px 16px;
  background: var(--surface-dim);
  border-bottom: 1px solid var(--outline);
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.interaction-meta {
  display: flex;
  align-items: center;
  gap: 12px;
  font-size: 12px;
  color: var(--on-surface-variant);
}

.interaction-icon {
  display: flex;
  align-items: center;
  color: var(--primary);
}

.interaction-tool-name {
  font-weight: 600;
  color: var(--on-surface);
}

.interaction-time {
  display: flex;
  align-items: center;
  gap: 4px;
}

.interaction-target {
  font-family: var(--font-mono);
  font-size: 13px;
  color: var(--tertiary);
}

.interaction-command {
  font-family: var(--font-mono);
  font-size: 13px;
  color: var(--on-surface);
  background: var(--surface-container);
  padding: 4px 8px;
  border-radius: 4px;
}

.interaction-body {
  padding: 0;
}

.interaction-code-block pre,
.interaction-terminal-output pre {
  margin: 0;
  padding: 16px;
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.6;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-all;
}

.interaction-code-block pre {
  background: var(--surface);
  color: var(--on-surface);
}

.interaction-terminal-output .stdout {
  background: #000;
  color: #fff;
}

.interaction-terminal-output .stderr {
  background: #2a0000;
  color: #ff8080;
}

.interaction-empty {
  padding: 16px;
  font-style: italic;
  color: var(--on-surface-variant);
  font-size: 13px;
}

.timeline-loading, .timeline-error {
  padding: 32px;
  text-align: center;
  color: var(--on-surface-variant);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}

.timeline-error {
  color: var(--error);
}

