@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=JetBrains+Mono:wght@400;500&family=Space+Grotesk:wght@500&display=swap');
@import './tokens.css';

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  background: var(--background);
  color: var(--on-surface);
  font-family: var(--font-body);
  font-size: 14px;
  line-height: 1.5;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}

a { color: var(--primary); text-decoration: none; transition: opacity 0.2s; }
a:hover { opacity: 0.8; text-decoration: none; }

.app-layout {
  display: flex;
  min-height: 100vh;
}

.sidebar {
  width: 240px;
  border-right: 1px solid var(--outline);
  display: flex;
  flex-direction: column;
  position: sticky;
  top: 0;
  height: 100vh;
  background: var(--background);
  flex-shrink: 0;
}

.sidebar-header {
  height: 56px;
  padding: 0 16px;
  display: flex;
  align-items: center;
  gap: 12px;
  border-bottom: 1px solid var(--outline);
}

.sidebar-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px 0;
}

.sidebar-section {
  margin-bottom: 24px;
}

.sidebar-section-title {
  padding: 0 16px;
  font-size: 11px;
  font-weight: 600;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 8px;
}

.sidebar-nav {
  display: flex;
  flex-direction: column;
}

.sidebar-nav-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 8px 16px;
  color: var(--on-surface);
  font-size: 13px;
  font-weight: 500;
  transition: background 0.2s;
}

.sidebar-nav-item:hover {
  background: var(--surface-dim);
  opacity: 1;
}

::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: var(--outline);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--on-surface-variant);
}

.sidebar-nav-item.active {
  background: var(--surface-dim);
  color: var(--on-surface);
  border-right: 2px solid var(--primary);
}


.sidebar-nav-item svg {
  color: var(--on-surface-variant);
}

.sidebar-nav-item.active svg {
  color: var(--primary);
}

.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.header {
  border-bottom: 1px solid var(--outline);
  padding: 0 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 56px;
  position: sticky;
  top: 0;
  background: var(--background);
  z-index: 10;
}

.container { width: 100%; max-width: 1400px; margin: 0 auto; padding: 32px 48px; }


.page-title {
  font-family: var(--font-headline);
  font-size: 24px;
  font-weight: 500;
  letter-spacing: -0.02em;
  margin-bottom: 32px;
  color: var(--on-surface);
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 16px;
  margin-bottom: 40px;
}
.stat-card {
  background: var(--surface-container);
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  padding: 24px;
}
.stat-label {
  font-size: 11px;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 12px;
  font-family: var(--font-headline);
}
.stat-value {
  font-size: 32px;
  font-weight: 500;
  color: var(--on-surface);
  line-height: 1;
  font-family: var(--font-headline);
  letter-spacing: -0.02em;
}
.stat-sub {
  font-size: 12px;
  color: var(--on-surface-variant);
  margin-top: 8px;
}

.charts-grid {
