  left: 16px;
  top: 0;
  bottom: 0;
  width: 1px;
  background: var(--outline);
  z-index: 0;
}

.timeline-item {
  display: flex;
  gap: 24px;
  position: relative;
  z-index: 1;
}

.timeline-dot {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--background);
  border: 1px solid var(--outline);
