  padding: 12px;
  border-radius: 6px;
  overflow-x: auto;
  font-family: var(--font-mono);
  font-size: 13px;
  margin-bottom: 12px;
  border: 1px solid var(--outline);
}

.message-text code {
  background: var(--surface-dim);
  padding: 2px 4px;
  border-radius: 4px;
  font-family: var(--font-mono);
  font-size: 13px;
}

.message-text pre code {
