}

.message-text h1, .message-text h2, .message-text h3, .message-text h4 {
  margin-top: 16px;
  margin-bottom: 12px;
  font-family: var(--font-headline);
}

.tool-call {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-top: 12px;
}

.tool-call-header {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 13px;
  font-weight: 500;
  color: var(--on-surface);
  cursor: pointer;
}

.tool-call-content {
  background: var(--surface-dim);
  border: 1px solid var(--outline);
  border-radius: 4px;
  padding: 12px;
  font-family: var(--font-mono);
  font-size: 12px;
  overflow-x: auto;
}

.detail-sidebar-section {
  margin-bottom: 32px;
}

.detail-sidebar-title {
  font-size: 11px;
  font-weight: 600;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 12px;
}

.filter-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.filter-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: 13px;
  color: var(--on-surface);
}

.filter-item input {
  width: 14px;
  height: 14px;
}

/* Session tabs */
.session-tabs {
  display: flex;
  align-items: center;
  border-bottom: 1px solid var(--outline);
  margin-bottom: 32px;
  margin-top: -24px;
}

.session-tab {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 16px;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  font-size: 14px;
  font-weight: 500;
  color: var(--on-surface-variant);
  cursor: pointer;
  margin-bottom: -1px;
  transition: color 0.15s;
}

.session-tab:hover { color: var(--on-surface); }

.session-tab.active {
  color: var(--on-surface);
  border-bottom-color: var(--primary);
}

.tab-badge {
  background: var(--surface-container);
  border: 1px solid var(--outline);
  border-radius: 10px;
  padding: 1px 7px;
  font-size: 11px;
  font-weight: 500;
  color: var(--on-surface-variant);
}

/* Changes tab layout */
.changes-layout {
  display: grid;
  grid-template-columns: 280px 1fr;
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  overflow: hidden;
  min-height: 500px;
}

.changes-file-list {
  border-right: 1px solid var(--outline);
  overflow-y: auto;
  background: var(--surface);
}

.changes-file-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  cursor: pointer;
  border-bottom: 1px solid var(--outline);
  transition: background 0.15s;
}

.changes-file-item:hover { background: var(--surface-dim); }
.changes-file-item.selected { background: var(--surface-container); }

.file-status-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  border-radius: 3px;
  font-size: 10px;
  font-weight: 700;
  flex-shrink: 0;
}

.status-M { background: rgba(59, 130, 246, 0.15); color: var(--primary); }
.status-A { background: rgba(34, 197, 94, 0.15); color: var(--tertiary); }
.status-D { background: rgba(248, 113, 113, 0.15); color: var(--error); }
.status-R { background: rgba(245, 158, 11, 0.15); color: #F59E0B; }

.changes-file-name {
  flex: 1;
  min-width: 0;
  overflow: hidden;
}

.changes-file-name > span:first-child {
  display: block;
  font-size: 13px;
  color: var(--on-surface);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.changes-file-dir {
  display: block;
  font-size: 11px;
  color: var(--on-surface-variant);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.changes-file-stats {
  display: flex;
  gap: 6px;
  flex-shrink: 0;
  font-size: 12px;
  font-family: var(--font-mono);
}

.stat-add { color: var(--tertiary); }
.stat-del { color: var(--error); }

/* Diff viewer */
.changes-diff-panel {
  overflow: auto;
  background: var(--background);
}

.diff-viewer {
  font-family: var(--font-mono);
  font-size: 12px;
}

.diff-file-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 16px;
  border-bottom: 1px solid var(--outline);
  background: var(--surface-dim);
  position: sticky;
  top: 0;
  z-index: 1;
}

.diff-file-path {
  font-size: 13px;
  font-weight: 500;
  color: var(--on-surface);
  font-family: var(--font-mono);
}

.diff-file-stats {
  display: flex;
  gap: 8px;
  font-family: var(--font-mono);
  font-size: 12px;
}

.diff-hunk-header {
  padding: 4px 12px;
  background: rgba(59, 130, 246, 0.07);
  color: var(--on-surface-variant);
  font-size: 12px;
  font-family: var(--font-mono);
  border-top: 1px solid var(--outline);
  border-bottom: 1px solid var(--outline);
}

.diff-table {
  width: 100%;
  border-collapse: collapse;
}

.diff-line-num {
  width: 44px;
  min-width: 44px;
  text-align: right;
  padding: 1px 8px;
  color: var(--on-surface-variant);
  user-select: none;
  font-size: 11px;
  border-right: 1px solid var(--outline);
  vertical-align: top;
  opacity: 0.6;
}

.diff-line-marker {
  width: 20px;
  min-width: 20px;
  text-align: center;
  padding: 1px 4px;
  font-size: 12px;
  user-select: none;
  border-right: 1px solid var(--outline);
  vertical-align: top;
}

.diff-line-content {
  padding: 1px 8px;
  white-space: pre;
  tab-size: 2;
  font-size: 12px;
  vertical-align: top;
  width: 100%;
}

.diff-line-add .diff-line-num,
.diff-line-add .diff-line-marker,
.diff-line-add .diff-line-content { background: rgba(34, 197, 94, 0.07); }
.diff-line-add .diff-line-marker,
.diff-line-add .diff-line-content { color: var(--tertiary); }

.diff-line-remove .diff-line-num,
.diff-line-remove .diff-line-marker,
.diff-line-remove .diff-line-content { background: rgba(248, 113, 113, 0.07); }
.diff-line-remove .diff-line-marker,
.diff-line-remove .diff-line-content { color: var(--error); }

.diff-empty {
  padding: 48px;
  text-align: center;
  color: var(--on-surface-variant);
  font-size: 13px;
}



/* Context Timeline */
.context-timeline {
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding: 24px 0;
}

.interaction-item {
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  overflow: hidden;
  background: var(--surface);
}

.interaction-header {
  padding: 12px 16px;
  background: var(--surface-dim);
  border-bottom: 1px solid var(--outline);
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.interaction-meta {
  display: flex;
  align-items: center;
  gap: 12px;
  font-size: 12px;
  color: var(--on-surface-variant);
}

.interaction-icon {
  display: flex;
  align-items: center;
  color: var(--primary);
}

.interaction-tool-name {
  font-weight: 600;
  color: var(--on-surface);
}

.interaction-time {
  display: flex;
  align-items: center;
  gap: 4px;
}

.interaction-target {
  font-family: var(--font-mono);
  font-size: 13px;
  color: var(--tertiary);
}

.interaction-command {
  font-family: var(--font-mono);
  font-size: 13px;
  color: var(--on-surface);
  background: var(--surface-container);
  padding: 4px 8px;
  border-radius: 4px;
}

.interaction-body {
  padding: 0;
}

.interaction-code-block pre,
.interaction-terminal-output pre {
  margin: 0;
  padding: 16px;
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.6;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-all;
}

.interaction-code-block pre {
  background: var(--surface);
  color: var(--on-surface);
}

.interaction-terminal-output .stdout {
  background: #000;
  color: #fff;
}

.interaction-terminal-output .stderr {
  background: #2a0000;
  color: #ff8080;
}

.interaction-empty {
  padding: 16px;
  font-style: italic;
  color: var(--on-surface-variant);
  font-size: 13px;
}

.timeline-loading, .timeline-error {
  padding: 32px;
  text-align: center;
  color: var(--on-surface-variant);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}

.timeline-error {
  color: var(--error);
}

